class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str):
        """Inserts a word into the trie."""
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word: str) -> bool:
        """Returns True if the word is in the trie."""
        node = self.root
        for char in word:
            if char not in node.children:
                return False
            node = node.children[char]
        return node.is_end_of_word

    def starts_with(self, prefix: str) -> bool:
        """Returns True if there is any word in the trie that starts with the given prefix."""
        node = self.root
        for char in prefix:
            if char not in node.children:
                return False
            node = node.children[char]
        return True

def find_longest_word(words):
    # 1. Initialize Trie and insert all words
    trie = Trie()
    for word in words:
        trie.insert(word)

    longest_word = ""

    def dfs(current_node, current_word):
        nonlocal longest_word

        # Update the longest word found so far
        # We prioritize longer words, then lexicographically smaller words if lengths are equal
        if len(current_word) > len(longest_word):
            longest_word = current_word
        elif len(current_word) == len(longest_word):
            longest_word = min(longest_word, current_word)

